Step 6: Determine Selected_Mechanism based on decision rules:
if ML < MT:
    if PV > VT:
        if MCI > MCT_high: Selected_Mechanism = 'IPA'
        else if MCT_low < MCI <= MCT_high: Selected_Mechanism = 'WAM'
        else: Selected_Mechanism = 'CFRM'
    else: Selected_Mechanism = 'APM'
else:
    if PV <= VT:
        if MCI > MCT_high: Selected_Mechanism = 'IPA'
        else if MCT_low < MCI <= MCT_high: Selected_Mechanism = 'MPAS'
        else: Selected_Mechanism = 'NBS'
    else:
        if MCI > MCT_high: Selected_Mechanism = 'COLM'
        else if MCT_low < MCI <= MCT_high: Selected_Mechanism = 'MMP'
        else: Selected_Mechanism = 'CGT'
